  if (gs.includes('PRE') || gs.includes('WARMUP') || gs.includes('SCHEDULED')) return 'SCHEDULED';
  if (gs.includes('PROGRESS') || gs.includes('LIVE')) return 'LIVE';
  if (item.inning && item.inning > 0) return 'LIVE';
  return 'SCHEDULED';
}

